var maximumLength = function(nums) {
    const map = new Map();

    for (const num of nums) {
        map.set(num, (map.get(num) || 0) + 1);
    }

    let ones = map.get(1) || 1;

    if (ones % 2 === 0) {
        ones--;
    }

    let res = ones;

    for (const [i, c] of map) {
        if (i === 1) continue;

        let num = i;
        let count = c;
        let turns = 1;

        while (count > 1) {
            num = Math.pow(num, Math.pow(2, turns));
            count = map.get(num) || 0;
            turns++;
        }

        res = Math.max(res, 2 * turns - 1);
    }

    return res;
};
